update video_access_log
video_id = #{bean.videoId}, user_id = #{bean.userId}, ip_address = #{bean.ipAddress}, user_agent = #{bean.userAgent}, referer = #{bean.referer},
where id = #{id}

mapper.select:
SELECT count(1) FROM video_access_log
WHERE video_id = #{videoId} AND ip_address = #{ipAddress}
AND access_time >= #{sinceTime}

SELECT DATE(access_time) as date, COUNT(*) as views,
       COUNT(DISTINCT ip_address) as unique_ips
FROM video_access_log
WHERE video_id = #{videoId}

    AND access_time >= #{startDate}


    AND access_time <= #{endDate}

GROUP BY DATE(access_time)
ORDER BY date DESC
